/**
 * ArtificRealm map slash commands.
 * Registers map actions that write to stat_data.World through MVU's functional updater.
 */
(function () {
    const SCRIPT_NAME = 'ArtificRealm MapCommands';
    const COMMAND_NAMES = ['startjourney', 'arrive', 'addtravelhours', 'addpin', 'revealfog', 'addtraveloption'];
    const INTERNAL_KEYS = new Set(['$meta', '$key', 'template']);

    if (window.__artificRealmMapCommandsRegistered) return;

    function isReady() {
        return typeof SlashCommandParser !== 'undefined'
            && typeof SlashCommand !== 'undefined'
            && typeof getVariables === 'function'
            && typeof updateVariablesWith === 'function';
    }

    function clone(value) {
        if (typeof structuredClone === 'function') return structuredClone(value);
        return JSON.parse(JSON.stringify(value || {}));
    }

    function getMessageId(rawArgs, context) {
        return rawArgs?.message_id ?? rawArgs?.messageId ?? context?.message_id ?? context?.messageId ?? null;
    }

    function normalizeArgs(rawArgs, value, context) {
        if (rawArgs && typeof rawArgs === 'object' && !Array.isArray(rawArgs)) {
            const args = { ...rawArgs };
            delete args.message_id;
            delete args.messageId;
            return args;
        }
        if (context?.namedArgs && typeof context.namedArgs === 'object') return { ...context.namedArgs };
        if (value && typeof value === 'object' && !Array.isArray(value)) return { ...value };
        return {};
    }

    function numberArg(args, key) {
        const value = Number(args[key]);
        return Number.isFinite(value) ? value : NaN;
    }

    function ensureWorld(stat) {
        if (!stat.World || typeof stat.World !== 'object') stat.World = {};
        return stat.World;
    }

    function formatNumber(value) {
        return Number.isInteger(value) ? String(value) : String(Number(value.toFixed(1)));
    }

    function generateMapItemKey(collection, prefix) {
        let key;
        do {
            key = prefix + '_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
        } while (collection && Object.prototype.hasOwnProperty.call(collection, key));
        return key;
    }

    function findByName(collection, name) {
        const wanted = String(name || '').toLowerCase();
        return Object.entries(collection || {}).find(([key, item]) => {
            if (INTERNAL_KEYS.has(key) || !item || typeof item !== 'object') return false;
            return String(item.Name || '').toLowerCase() === wanted;
        });
    }

    function findVehicle(collection, vehicleName) {
        const wanted = String(vehicleName || '');
        const byKey = Object.entries(collection || {}).find(([key, item]) => !INTERNAL_KEYS.has(key) && key === wanted && item && typeof item === 'object');
        if (byKey) return byKey;
        return findByName(collection, wanted);
    }

    function getContext(rawArgs, context) {
        const messageId = getMessageId(rawArgs, context);
        return messageId !== null && messageId !== undefined && messageId !== '' ? { type: 'message', message_id: messageId } : undefined;
    }

    function readStatData(context) {
        const messageVars = context ? getVariables(context) : null;
        const globalVars = getVariables();
        return clone(messageVars?.stat_data || globalVars?.stat_data || {});
    }

    async function mutate(rawArgs, value, context, handler) {
        const updateContext = getContext(rawArgs, context);
        const args = normalizeArgs(rawArgs, value, context);
        const stat = readStatData(updateContext);
        const next = handler(stat, args);
        if (next.error) return next.error;
        await updateVariablesWith((variables) => {
            const vars = variables || {};
            const current = clone(vars.stat_data || stat || {});
            const result = handler(current, args);
            if (result.error) return vars;
            vars.stat_data = current;
            return vars;
        }, updateContext);
        return next.message;
    }

    function startJourney(stat, args) {
        const destX = numberArg(args, 'destx');
        const destY = numberArg(args, 'desty');
        if (!Number.isFinite(destX) || !Number.isFinite(destY)) return { error: 'Error: destx/desty must be numbers' };

        const world = ensureWorld(stat);
        const vehicleInput = String(args.vehicle || '');
        const vehicleEntry = findVehicle(world.TravelOptions || {}, vehicleInput);
        if (!vehicleEntry) return { error: "Error: vehicle '" + vehicleInput + "' not found" };

        const vehicle = vehicleEntry[1];
        const origin = world.PartyPosition || { X: 0, Y: 0 };
        const originX = Number(origin.X) || 0;
        const originY = Number(origin.Y) || 0;
        const speed = Number(vehicle.Speed) || 0;
        const destName = String(args.destname || '');
        const dx = destX - originX;
        const dy = destY - originY;
        const distanceKm = Math.sqrt(dx * dx + dy * dy) * 50;
        const etaHours = speed > 0 ? distanceKm / speed : 0;

        world.Travel = {
            Active: true,
            OriginX: originX,
            OriginY: originY,
            DestX: destX,
            DestY: destY,
            DestName: destName,
            VehicleName: String(vehicle.Name || vehicleEntry[0]),
            VehicleMode: String(vehicle.Mode || ''),
            SpeedKmh: speed,
            ElapsedHours: 0,
        };
        return { message: 'Journey started toward ' + destName + ' (' + formatNumber(distanceKm) + 'km, ~' + formatNumber(etaHours) + 'h)' };
    }

    function arrive(stat) {
        const world = ensureWorld(stat);
        const travel = world.Travel || {};
        if (travel.Active !== true) return { error: 'Error: no active journey' };
        world.PartyPosition = { X: Number(travel.DestX) || 0, Y: Number(travel.DestY) || 0 };
        travel.Active = false;
        return { message: 'Arrived at ' + String(travel.DestName || 'destination') };
    }

    function addTravelHours(stat, args) {
        const hours = numberArg(args, 'hours');
        if (!Number.isFinite(hours) || hours <= 0) return { error: 'Error: hours must be a positive number' };
        const world = ensureWorld(stat);
        const travel = world.Travel || {};
        if (travel.Active !== true) return { error: 'Error: no active journey' };
        travel.ElapsedHours = (Number(travel.ElapsedHours) || 0) + hours;
        return { message: 'Added ' + formatNumber(hours) + 'h (total elapsed: ' + formatNumber(travel.ElapsedHours) + 'h)' };
    }

    function addPin(stat, args) {
        const x = numberArg(args, 'x');
        const y = numberArg(args, 'y');
        if (!Number.isFinite(x) || !Number.isFinite(y)) return { error: 'Error: x/y must be numbers' };
        const world = ensureWorld(stat);
        if (!world.MapPins || typeof world.MapPins !== 'object') world.MapPins = {};
        const name = String(args.name || 'New Pin');
        const key = generateMapItemKey(world.MapPins, 'pin');
        world.MapPins[key] = {
            Name: name,
            X: x,
            Y: y,
            Note: String(args.note || ''),
            Icon: String(args.icon || 'pin'),
        };
        return { message: "Pin '" + name + "' added at (" + formatNumber(x) + ',' + formatNumber(y) + ')' };
    }

    function revealFog(stat, args) {
        const world = ensureWorld(stat);
        const requestedName = String(args.name || '');
        const entry = findByName(world.FogRegions || {}, requestedName);
        if (!entry) return { error: "Error: fog region '" + requestedName + "' not found" };
        entry[1].Revealed = true;
        return { message: "Fog region '" + String(entry[1].Name || requestedName) + "' revealed" };
    }

    function addTravelOption(stat, args) {
        const speed = numberArg(args, 'speed');
        if (!Number.isFinite(speed)) return { error: 'Error: speed must be a number' };
        const world = ensureWorld(stat);
        if (!world.TravelOptions || typeof world.TravelOptions !== 'object') world.TravelOptions = {};
        const name = String(args.name || 'New Vehicle');
        const mode = String(args.mode || 'Walking');
        const key = generateMapItemKey(world.TravelOptions, 'vehicle');
        world.TravelOptions[key] = { Name: name, Mode: mode, Speed: speed };
        return { message: "Travel option '" + name + "' added (" + mode + ', ' + formatNumber(speed) + 'km/h)' };
    }

    function registerCommand(name, handler, helpString) {
        SlashCommandParser.addCommandObject(SlashCommand.fromProps({
            name,
            callback: (rawArgs, value, context) => mutate(rawArgs, value, context, handler),
            helpString,
        }));
    }

    function registerAll() {
        if (!isReady()) {
            setTimeout(registerAll, 1000);
            return;
        }
        COMMAND_NAMES.forEach((name) => {
            if (name === 'startjourney') registerCommand(name, startJourney, 'Start map travel: /startjourney destx= desty= destname= vehicle=');
            if (name === 'arrive') registerCommand(name, arrive, 'Arrive at the active map journey destination.');
            if (name === 'addtravelhours') registerCommand(name, addTravelHours, 'Advance active map travel: /addtravelhours hours=');
            if (name === 'addpin') registerCommand(name, addPin, 'Add a map pin: /addpin name= x= y= note= icon=');
            if (name === 'revealfog') registerCommand(name, revealFog, 'Reveal a fog region by name: /revealfog name=');
            if (name === 'addtraveloption') registerCommand(name, addTravelOption, 'Add a travel option: /addtraveloption name= mode= speed=');
        });
        window.__artificRealmMapCommandsRegistered = true;
        console.log('[' + SCRIPT_NAME + '] registered ' + COMMAND_NAMES.length + ' commands.');
    }

    registerAll();
}());

